## Step 4: Data Model

### Metric Data Point

```javascript
// A single metric data point
const dataPoint = {
  metric: 'http.request.duration',     // metric name
  type: 'histogram',                   // counter, gauge, histogram
  value: 142.5,                        // numeric value (ms)
  timestamp: 1710720000,               // Unix timestamp (seconds)
  tags: {                              // dimensions/labels
    host: 'web-server-42',
    service: 'user-api',
    method: 'GET',
    path: '/api/users',
    status_code: '200',
    region: 'us-east-1',
  },
};
```

### Time Series Identity

A unique time series is identified by (metric_name, sorted_tags). This is the "cardinality" of the system:

```javascript
function timeSeriesId(metric, tags) {
  const sortedTags = Object.entries(tags)
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([k, v]) => `${k}=${v}`)
    .join(',');
  return `${metric}{${sortedTags}}`;
}

// Example:
// http.request.duration{host=web-42,method=GET,path=/api/users,region=us-east-1,service=user-api,status_code=200}
```

## Step 5: API Design

```javascript
import express from 'express';

const app = express();

// POST /api/v1/metrics - Ingest metrics (used by agents)
app.post('/api/v1/metrics', async (req, res) => {
  const { metrics } = req.body;
  // metrics: [{ metric, type, value, timestamp, tags }]

  if (!Array.isArray(metrics) || metrics.length === 0) {
    return res.status(400).json({ error: 'metrics array required' });
  }

  if (metrics.length > 10000) {
    return res.status(413).json({ error: 'Batch too large, max 10000' });
  }

  // Send to Kafka for async processing
  await kafkaProducer.send({
    topic: 'metrics-ingest',
    messages: metrics.map(m => ({
      key: timeSeriesId(m.metric, m.tags),
      value: JSON.stringify(m),
    })),
  });

  res.status(202).json({ accepted: metrics.length });
});

// POST /api/v1/query - Query metrics
app.post('/api/v1/query', async (req, res) => {
  const {
    metric,           // 'http.request.duration'
    aggregation,      // 'avg', 'sum', 'max', 'min', 'p99'
    groupBy,          // ['host', 'status_code']
    filters,          // { region: 'us-east-1', service: 'user-api' }
    startTime,        // ISO 8601 or Unix timestamp
    endTime,          // ISO 8601 or Unix timestamp
    granularity,      // '10s', '1m', '5m', '1h'
  } = req.body;

  const results = await queryService.execute({
    metric,
    aggregation,
    groupBy: groupBy || [],
    filters: filters || {},
    startTime: new Date(startTime),
    endTime: new Date(endTime),
    granularity: granularity || '1m',
  });

  res.json({
    metric,
    series: results, // [{ tags: {...}, datapoints: [[timestamp, value], ...] }]
  });
});

// POST /api/v1/alerts - Create alert rule
app.post('/api/v1/alerts', async (req, res) => {
  const {
    name,
    query,           // { metric, aggregation, filters, groupBy }
    condition,       // { operator: '>', threshold: 500 }
    window,          // '5m' (evaluate over last 5 minutes)
    notifyChannels,  // ['slack:#alerts', 'pagerduty:team-backend']
    severity,        // 'critical', 'warning', 'info'
  } = req.body;

  const alert = await alertService.create({
    name, query, condition, window, notifyChannels, severity,
  });

  res.status(201).json(alert);
});

// GET /api/v1/dashboards/:id - Get dashboard definition
app.get('/api/v1/dashboards/:id', async (req, res) => {
  const dashboard = await dashboardService.getById(req.params.id);
  if (!dashboard) return res.status(404).json({ error: 'Not found' });
  res.json(dashboard);
});
