## Core Implementation: Geospatial Matching

```javascript
import Redis from 'ioredis';

const redis = new Redis({ host: 'redis-cluster', port: 6379 });

class LocationService {
  // Update driver location using Redis GEO
  async updateDriverLocation(driverId, { lat, lng, heading, speed }) {
    // GEOADD stores location in a sorted set with geohash scoring
    await redis.geoadd('drivers:available', lng, lat, driverId.toString());

    // Store metadata separately
    await redis.hset(`driver:${driverId}:meta`, {
      lat: lat.toString(),
      lng: lng.toString(),
      heading: heading.toString(),
      speed: speed.toString(),
      updated_at: Date.now().toString(),
    });
  }

  // Find nearby available drivers
  async findNearbyDrivers(lat, lng, radiusKm = 5, limit = 10) {
    // GEOSEARCH returns drivers within radius, sorted by distance
    const results = await redis.geosearch(
      'drivers:available',
      'FROMLONLAT', lng, lat,
      'BYRADIUS', radiusKm, 'km',
      'ASC',
      'COUNT', limit,
      'WITHDIST',
      'WITHCOORD'
    );

    return results.map(([driverId, distance, [driverLng, driverLat]]) => ({
      driver_id: driverId,
      distance_km: parseFloat(distance),
      lat: parseFloat(driverLat),
      lng: parseFloat(driverLng),
    }));
  }

  // Remove driver from available pool
  async removeFromAvailable(driverId) {
    await redis.zrem('drivers:available', driverId.toString());
  }
}

class MatchingService {
  constructor(locationService, rideService) {
    this.locationService = locationService;
    this.rideService = rideService;
  }

  async findDriver(ride) {
    const candidates = await this.locationService.findNearbyDrivers(
      ride.pickup_lat,
      ride.pickup_lng,
      5, // 5km radius
      20  // top 20 candidates
    );

    if (candidates.length === 0) {
      // Expand search radius or notify rider
      await this.rideService.updateStatus(ride.id, 'no_drivers');
      return null;
    }

    // Score candidates: lower distance + higher rating = better match
    const scored = await Promise.all(
      candidates.map(async (c) => {
        const driver = await this.getDriverProfile(c.driver_id);
        return {
          ...c,
          score: c.distance_km * 0.7 - (driver.rating_avg * 0.3),
          vehicle_type: driver.vehicle_type,
        };
      })
    );

    // Filter by vehicle type and sort by score
    const matched = scored
      .filter(s => s.vehicle_type === ride.vehicle_type)
      .sort((a, b) => a.score - b.score);

    // Try to lock the best driver (prevent double-matching)
    for (const candidate of matched) {
      const locked = await this.lockDriver(candidate.driver_id, ride.id);
      if (locked) {
        await this.rideService.assignDriver(ride.id, candidate.driver_id);
        await this.locationService.removeFromAvailable(candidate.driver_id);
        // Notify driver via WebSocket
        await this.notifyDriver(candidate.driver_id, ride);
        return candidate;
      }
    }

    return null; // No driver available after locking attempts
  }

  // Distributed lock to prevent double-matching
  async lockDriver(driverId, rideId) {
    // SET with NX (only if not exists) and EX (expire after 30s)
    const result = await redis.set(
      `driver_lock:${driverId}`,
      rideId.toString(),
      'EX', 30,
      'NX'
    );
    return result === 'OK';
  }
}

class PricingService {
  // Compute surge multiplier based on supply/demand in area
  async getSurgeMultiplier(pickup) {
    const geohash = this.computeGeohash(pickup.lat, pickup.lng, 6);

    // Count riders requesting in this zone (last 5 min)
    const demand = await redis.get(`demand:${geohash}`) || 0;
    // Count available drivers in this zone
    const supply = await this.locationService.findNearbyDrivers(
      pickup.lat, pickup.lng, 2
    );

    const ratio = parseInt(demand) / Math.max(supply.length, 1);

    if (ratio > 3) return 2.5;
    if (ratio > 2) return 2.0;
    if (ratio > 1.5) return 1.5;
    if (ratio > 1) return 1.25;
    return 1.0;
  }

  async estimateFare(pickup, dropoff, vehicleType, surge) {
    const distance = this.haversineDistance(pickup, dropoff);
    const baseFare = { standard: 2.50, xl: 4.00, premium: 6.00 };
    const perKm = { standard: 1.20, xl: 1.80, premium: 2.50 };
    const perMin = { standard: 0.30, xl: 0.40, premium: 0.60 };
    const estimatedMinutes = (distance / 30) * 60; // Assume 30 km/h avg

    const fare =
      baseFare[vehicleType] +
      distance * perKm[vehicleType] +
      estimatedMinutes * perMin[vehicleType];

    return Math.round(fare * surge * 100) / 100;
  }

  haversineDistance(point1, point2) {
    const R = 6371; // Earth radius in km
    const dLat = ((point2.lat - point1.lat) * Math.PI) / 180;
    const dLng = ((point2.lng - point1.lng) * Math.PI) / 180;
    const a =
      Math.sin(dLat / 2) ** 2 +
      Math.cos((point1.lat * Math.PI) / 180) *
      Math.cos((point2.lat * Math.PI) / 180) *
      Math.sin(dLng / 2) ** 2;
    return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  }

  computeGeohash(lat, lng, precision) {
    // Simplified: in production use ngeohash library
    return `${Math.floor(lat * 10)}:${Math.floor(lng * 10)}`;
  }
}
```

## Real-Time Communication with WebSockets

```javascript
import { WebSocketServer } from 'ws';
import Redis from 'ioredis';

const sub = new Redis();
const pub = new Redis();
const connections = new Map();

const wss = new WebSocketServer({ port: 8080 });

wss.on('connection', (ws, req) => {
  const userId = authenticateWS(req);
  connections.set(userId, ws);

  ws.on('close', () => connections.delete(userId));
});

// Subscribe to ride updates via Redis Pub/Sub
sub.psubscribe('ride:*');
sub.on('pmessage', (pattern, channel, message) => {
  const rideId = channel.split(':')[1];
  const data = JSON.parse(message);

  // Forward to connected rider/driver
  const riderWs = connections.get(data.rider_id);
  const driverWs = connections.get(data.driver_id);

  if (riderWs) riderWs.send(JSON.stringify(data));
  if (driverWs) driverWs.send(JSON.stringify(data));
});

// Publish location updates from driver service
async function broadcastDriverLocation(rideId, driverId, location) {
  await pub.publish(`ride:${rideId}`, JSON.stringify({
    type: 'driver_location',
    driver_id: driverId,
    ...location,
    timestamp: Date.now(),
  }));
}
```

## Scaling Strategies

### Geospatial Partitioning

```
┌───────────────────────────────────────────────┐
│  City-Level Partitioning                       │
│                                                │
│  Each major city gets its own:                 │
│    - Redis instance (driver locations)         │
│    - Matching service (local matching)         │
│    - Surge calculator                          │
│                                                │
│  ┌─────────┐  ┌──────────┐  ┌──────────┐     │
│  │ NYC     │  │ SF       │  │ London   │     │
│  │ Cluster │  │ Cluster  │  │ Cluster  │     │
│  └─────────┘  └──────────┘  └──────────┘     │
│                                                │
│  Global services:                              │
│    - User accounts, payment, trip history      │
└───────────────────────────────────────────────┘
```

### Trip State Machine

```
 requested ──> matching ──> driver_assigned ──> driver_en_route
     │                           │                    │
     ▼                           ▼                    ▼
  cancelled              cancelled/timeout         arrived
                                                      │
                                                      ▼
                                                  in_progress
                                                      │
                                                      ▼
                                                  completed ──> payment ──> rated
```

## Trade-offs

| Decision | Option A | Option B |
|---|---|---|
| **Location store** | Redis GEO | PostGIS |
| | In-memory, sub-ms, volatile | Persistent, slower, full SQL |
| **Matching** | Nearest available | Batched optimization |
| | Instant match, locally optimal | 30s batches, globally optimal |
| **Real-time updates** | WebSocket | Server-Sent Events |
| | Bidirectional, complex | Simpler, one-way (rider only) |
| **Surge pricing** | Real-time (per request) | Zone-based (pre-computed) |
| | Accurate, expensive computation | Slightly stale, very fast |
| **Trip storage** | PostgreSQL | DynamoDB |
| | Relational, complex queries | Key-value, unlimited scale |

## Summary

A ride-sharing system requires real-time geospatial indexing (Redis GEO), distributed locking for driver matching, WebSocket connections for live tracking, and a state machine for trip lifecycle management. The system partitions naturally by city/region. Surge pricing uses supply/demand ratios computed from geohash-bucketed zones. The critical path — matching a rider with a driver — must use Redis-based locking to prevent double-assignment. Location data flows through Redis Pub/Sub to deliver real-time updates to both parties.

9.5.3.body:
# Design an Online Code Editor (Replit)

## Introduction

An online code editor allows users to write, run, and share code entirely in the browser — no local setup required. Platforms like Replit, CodeSandbox, and StackBlitz handle millions of users running code in dozens of programming languages. This is a fascinating system design problem because it combines real-time collaboration, remote code execution in sandboxed environments, file system management, and terminal streaming.

In a system design interview, this problem tests your understanding of container orchestration, WebSocket-based real-time communication, sandboxed execution, and resource management.

## Requirements

### Functional Requirements

1. **Create projects (repls)** — Users create projects with a chosen language/template
2. **File editor** — Create, edit, rename, delete files with syntax highlighting
3. **Code execution** — Run code and see output in a terminal panel
4. **Terminal access** — Full interactive terminal (shell) connected to the sandbox
5. **Real-time collaboration** — Multiple users edit the same project simultaneously (cursors, selections)
6. **Package management** — Install dependencies (npm install, pip install)
7. **Share and embed** — Share projects via URL, embed in websites
8. **Version history** — View and restore previous versions of files
9. **Persistent storage** — Projects persist across sessions

### Non-Functional Requirements

1. **Low latency editing** — Keystrokes must appear in <50ms (local-first)
2. **Execution isolation** — User code cannot affect other users or the host system
3. **Resource limits** — CPU, memory, disk, and network limits per sandbox
4. **Scalability** — Support 100K concurrent active sandboxes
5. **High availability** — 99.9% uptime for the editor; execution environments can be recreated

## Capacity Estimation

```
Registered users:              10 million
Daily active users:            500,000
Concurrent editing sessions:   100,000
Concurrent running sandboxes:  50,000

Sandbox resources (per user):
  - CPU: 0.5 vCPU
  - Memory: 512 MB
  - Disk: 1 GB
  - Network: 10 Mbps

Total compute for 50K sandboxes:
  - CPU: 50K * 0.5 = 25,000 vCPUs
  - Memory: 50K * 512MB = 25 TB
  - Disk: 50K * 1GB = 50 TB (mostly SSD)

File operations:
  - File saves: 100K users * 1 save/10s = 10,000 writes/sec
  - File reads: 100K * 1 read/5s = 20,000 reads/sec

WebSocket messages:
  - Keystrokes: 100K users * 5 keystrokes/sec = 500,000 msg/sec
  - Terminal output: 50K sandboxes * 2 msg/sec = 100,000 msg/sec
  - Total: ~600,000 WebSocket messages/sec

Storage:
  - Avg project size: 10 MB
  - Total projects: 50M projects * 10MB = 500 TB
  - Use object storage (S3) for cold projects, SSD for active
```

## High-Level Architecture

```
┌──────────────────────────────────────────────────────────────┐
│                     Client (Browser)                          │
│  ┌──────────┐  ┌──────────────┐  ┌────────────────────────┐  │
│  │  Monaco   │  │  Terminal    │  │  Collaboration         │  │
│  │  Editor   │  │  (xterm.js)  │  │  (CRDT / OT engine)   │  │
│  └────┬──────┘  └──────┬───────┘  └──────────┬────────────┘  │
│       │                │                      │               │
└───────┼────────────────┼──────────────────────┼───────────────┘
        │  WebSocket     │  WebSocket            │  WebSocket
        │                │                      │
┌───────▼────────────────▼──────────────────────▼───────────────┐
│                  API Gateway / Load Balancer                    │
└──────────┬─────────────┬──────────────────────┬───────────────┘
           │             │                      │
     ┌─────▼─────┐ ┌────▼──────┐ ┌─────────────▼──────────┐
     │  Project   │ │ Execution │ │  Collaboration          │
     │  Service   │ │ Service   │ │  Service                │
     │            │ │           │ │  (CRDT sync)            │
     └─────┬──────┘ └────┬──────┘ └────────────┬────────────┘
           │             │                      │
     ┌─────▼─────┐ ┌────▼──────────────┐  ┌────▼─────────┐
     │PostgreSQL │ │ Container          │  │ Redis        │
     │(Projects, │ │ Orchestrator       │  │ (Presence,   │
     │ Users,    │ │ (K8s / Firecracker)│  │  CRDT state, │
     │ Versions) │ │                    │  │  Pub/Sub)    │
     └───────────┘ │  ┌──────┐ ┌─────┐ │  └──────────────┘
                   │  │Sandbox│ │Sand.│ │
     ┌───────────┐ │  │  VM 1 │ │VM 2 │ │
     │    S3     │ │  └──────┘ └─────┘ │
     │ (Project  │ └────────────────────┘
     │  files)   │
     └───────────┘
```

## API Design

```javascript
import express from 'express';
const router = express.Router();

// Create a new project (repl)
router.post('/projects', async (req, res) => {
  // POST /api/v1/projects
  // Body: { name, language, template?, description? }
  // Response: { project_id, name, language, url, sandbox_url }
  const project = await projectService.create({
    owner_id: req.user.id,
    name: req.body.name,
    language: req.body.language,
    template: req.body.template || 'blank',
  });
  res.status(201).json(project);
});

// Get project metadata and file tree
router.get('/projects/:projectId', async (req, res) => {
  // Response: { id, name, language, files: [...], collaborators, created_at }
  const project = await projectService.getWithFileTree(req.params.projectId);
  res.json(project);
});

// File operations
router.get('/projects/:projectId/files/*', async (req, res) => {
  // GET /api/v1/projects/:id/files/src/index.js
  const filePath = req.params[0];
  const content = await fileService.readFile(req.params.projectId, filePath);
  res.json({ path: filePath, content });
});

router.put('/projects/:projectId/files/*', async (req, res) => {
  // PUT /api/v1/projects/:id/files/src/index.js
  // Body: { content: string }
  const filePath = req.params[0];
  await fileService.writeFile(req.params.projectId, filePath, req.body.content);
  res.status(204).send();
});

router.post('/projects/:projectId/files', async (req, res) => {
  // Body: { path, content?, type: 'file' | 'directory' }
  await fileService.createFile(req.params.projectId, req.body);
  res.status(201).send();
});

router.delete('/projects/:projectId/files/*', async (req, res) => {
  const filePath = req.params[0];
  await fileService.deleteFile(req.params.projectId, filePath);
  res.status(204).send();
});

// Execute code / start sandbox
router.post('/projects/:projectId/run', async (req, res) => {
  // POST /api/v1/projects/:id/run
  // Body: { command?: string } (optional, defaults to language-specific run command)
  // Response: { sandbox_id, websocket_url }
  const sandbox = await executionService.startSandbox(
    req.params.projectId,
    req.body.command
  );
  res.json({
    sandbox_id: sandbox.id,
    websocket_url: `wss://exec.example.com/ws/${sandbox.id}`,
  });
});

// Stop sandbox
router.post('/projects/:projectId/stop', async (req, res) => {
  await executionService.stopSandbox(req.params.projectId);
  res.status(204).send();
});

// Version history
router.get('/projects/:projectId/versions', async (req, res) => {
  // Response: { versions: [{ id, timestamp, message, author }] }
  const versions = await versionService.listVersions(
    req.params.projectId,
    { cursor: req.query.cursor, limit: parseInt(req.query.limit) || 20 }
  );
  res.json(versions);
});

// Collaboration: add collaborator
router.post('/projects/:projectId/collaborators', async (req, res) => {
  // Body: { user_id, permission: 'read' | 'write' | 'admin' }
  await projectService.addCollaborator(
    req.params.projectId,
    req.body.user_id,
    req.body.permission
  );
  res.status(201).send();
});

// Share / fork
router.post('/projects/:projectId/fork', async (req, res) => {
  const forked = await projectService.fork(req.params.projectId, req.user.id);
  res.status(201).json(forked);
});

export default router;
```

## Database Schema

```sql
-- Users
CREATE TABLE users (
  id              BIGSERIAL PRIMARY KEY,
  username        VARCHAR(64) UNIQUE NOT NULL,
  email           VARCHAR(255) UNIQUE NOT NULL,
  plan            VARCHAR(16) DEFAULT 'free',  -- free, pro, teams
  created_at      TIMESTAMPTZ DEFAULT NOW()
);

-- Projects (Repls)
CREATE TABLE projects (
  id              BIGSERIAL PRIMARY KEY,
  owner_id        BIGINT NOT NULL REFERENCES users(id),
  name            VARCHAR(128) NOT NULL,
  slug            VARCHAR(128) NOT NULL,
  language        VARCHAR(32) NOT NULL,
  description     TEXT,
  is_public       BOOLEAN DEFAULT true,
  forked_from     BIGINT REFERENCES projects(id),
  storage_bucket  VARCHAR(255) NOT NULL,   -- S3 path for project files
  created_at      TIMESTAMPTZ DEFAULT NOW(),
  updated_at      TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE (owner_id, slug)
);
CREATE INDEX idx_project_owner ON projects(owner_id, updated_at DESC);
CREATE INDEX idx_project_language ON projects(language, is_public);

-- Collaborators
CREATE TABLE collaborators (
  project_id      BIGINT NOT NULL REFERENCES projects(id) ON DELETE CASCADE,
  user_id         BIGINT NOT NULL REFERENCES users(id),
  permission      VARCHAR(16) NOT NULL DEFAULT 'write',
  created_at      TIMESTAMPTZ DEFAULT NOW(),
  PRIMARY KEY (project_id, user_id)
);

-- File versions (snapshots)
CREATE TABLE file_versions (
  id              BIGSERIAL PRIMARY KEY,
  project_id      BIGINT NOT NULL REFERENCES projects(id) ON DELETE CASCADE,
  file_path       TEXT NOT NULL,
  content_hash    VARCHAR(64) NOT NULL,    -- SHA-256 of content
  size_bytes      INTEGER NOT NULL,
  author_id       BIGINT REFERENCES users(id),
  created_at      TIMESTAMPTZ DEFAULT NOW()
);
CREATE INDEX idx_file_version ON file_versions(project_id, file_path, created_at DESC);

-- Project snapshots (point-in-time versions)
CREATE TABLE project_snapshots (
  id              BIGSERIAL PRIMARY KEY,
  project_id      BIGINT NOT NULL REFERENCES projects(id) ON DELETE CASCADE,
  author_id       BIGINT REFERENCES users(id),
  message         TEXT,
  file_manifest   JSONB NOT NULL,   -- { "src/index.js": "hash1", "package.json": "hash2" }
  created_at      TIMESTAMPTZ DEFAULT NOW()
);
CREATE INDEX idx_snapshot_project ON project_snapshots(project_id, created_at DESC);

-- Sandbox sessions (active execution environments)
CREATE TABLE sandbox_sessions (
  id              BIGSERIAL PRIMARY KEY,
  project_id      BIGINT NOT NULL REFERENCES projects(id),
  user_id         BIGINT NOT NULL REFERENCES users(id),
  container_id    VARCHAR(128),
  node_hostname   VARCHAR(128),
  status          VARCHAR(16) DEFAULT 'starting', -- starting, running, stopped, crashed
  cpu_limit       DECIMAL(4,2) DEFAULT 0.50,
  memory_limit_mb INTEGER DEFAULT 512,
  started_at      TIMESTAMPTZ DEFAULT NOW(),
  stopped_at      TIMESTAMPTZ
);
CREATE INDEX idx_sandbox_project ON sandbox_sessions(project_id, status);
```

## Core Implementation: Sandbox Execution

```javascript
import { KubeConfig, CoreV1Api, AppsV1Api } from '@kubernetes/client-node';
import Redis from 'ioredis';

const redis = new Redis();

class ExecutionService {
  constructor() {
    const kc = new KubeConfig();
    kc.loadFromDefault();
    this.k8sCore = kc.makeApiClient(CoreV1Api);
  }

  async startSandbox(projectId, command) {
    // Check if sandbox already running
    const existing = await this.getActiveSandbox(projectId);
    if (existing) return existing;

    // Create a sandboxed container (pod) for this project
    const sandboxId = `sandbox-${projectId}-${Date.now()}`;
    const project = await projectService.get(projectId);

    const podSpec = {
      apiVersion: 'v1',
      kind: 'Pod',
      metadata: {
        name: sandboxId,
        labels: {
          app: 'sandbox',
          project: projectId.toString(),
          language: project.language,
        },
      },
      spec: {
        containers: [{
          name: 'sandbox',
          image: this.getImage(project.language),
          resources: {
            limits: { cpu: '500m', memory: '512Mi' },
            requests: { cpu: '100m', memory: '128Mi' },
          },
          // Mount project files from S3/PVC
          volumeMounts: [{
            name: 'project-files',
            mountPath: '/workspace',
          }],
          // Security: no root, no network escalation
          securityContext: {
            runAsNonRoot: true,
            runAsUser: 1000,
            readOnlyRootFilesystem: false,
            allowPrivilegeEscalation: false,
          },
        }],
        volumes: [{
          name: 'project-files',
          emptyDir: { sizeLimit: '1Gi' },
        }],
        // Auto-terminate after 1 hour of inactivity
        activeDeadlineSeconds: 3600,
        // Restrict network access
        dnsPolicy: 'None',
        dnsConfig: {
          nameservers: ['8.8.8.8'],
        },
      },
    };

    await this.k8sCore.createNamespacedPod('sandboxes', podSpec);

    // Sync project files to the sandbox
    await this.syncProjectFiles(sandboxId, projectId);

    // Record session
    const session = await prisma.sandbox_sessions.create({
      data: {
        project_id: BigInt(projectId),
        user_id: BigInt(project.owner_id),
        container_id: sandboxId,
        status: 'running',
      },
    });

    return { id: session.id, container_id: sandboxId };
  }

  getImage(language) {
    const images = {
      javascript: 'sandbox-node:20-alpine',
      typescript: 'sandbox-node:20-alpine',
      python: 'sandbox-python:3.12-alpine',
      go: 'sandbox-go:1.22-alpine',
      rust: 'sandbox-rust:1.76-alpine',
      java: 'sandbox-java:21-alpine',
    };
    return `registry.example.com/${images[language] || images.javascript}`;
  }

  async stopSandbox(projectId) {
    const session = await this.getActiveSandbox(projectId);
    if (!session) return;

    // Save any changed files back to S3
    await this.persistFiles(session.container_id, projectId);

    // Delete the pod
    await this.k8sCore.deleteNamespacedPod(session.container_id, 'sandboxes');

    await prisma.sandbox_sessions.update({
      where: { id: session.id },
      data: { status: 'stopped', stopped_at: new Date() },
    });
  }
}
```

## Real-Time Collaboration with CRDT

```javascript
import * as Y from 'yjs';
import { WebSocketServer } from 'ws';
import Redis from 'ioredis';

const pub = new Redis();
const sub = new Redis();

// Each project has a Yjs document
const docs = new Map();

function getOrCreateDoc(projectId) {
  if (!docs.has(projectId)) {
    const ydoc = new Y.Doc();
    docs.set(projectId, ydoc);
  }
  return docs.get(projectId);
}

const wss = new WebSocketServer({ port: 8081 });

wss.on('connection', (ws, req) => {
  const projectId = extractProjectId(req.url);
  const userId = authenticateWS(req);
  const ydoc = getOrCreateDoc(projectId);

  // Send current document state to new client
  const stateVector = Y.encodeStateAsUpdate(ydoc);
  ws.send(JSON.stringify({ type: 'sync', data: Array.from(stateVector) }));

  // Broadcast presence (cursor position, user info)
  pub.publish(`collab:${projectId}`, JSON.stringify({
    type: 'presence',
    user_id: userId,
    action: 'joined',
  }));

  ws.on('message', (message) => {
    const data = JSON.parse(message);

    if (data.type === 'update') {
      // Apply CRDT update from client
      const update = new Uint8Array(data.data);
      Y.applyUpdate(ydoc, update);

      // Broadcast to other clients in this project
      pub.publish(`collab:${projectId}`, JSON.stringify({
        type: 'update',
        data: Array.from(update),
        sender: userId,
      }));
    }

    if (data.type === 'cursor') {
      // Broadcast cursor position
      pub.publish(`collab:${projectId}`, JSON.stringify({
        type: 'cursor',
        user_id: userId,
        file: data.file,
        position: data.position,
        selection: data.selection,
      }));
    }
  });

  ws.on('close', () => {
    pub.publish(`collab:${projectId}`, JSON.stringify({
      type: 'presence',
      user_id: userId,
      action: 'left',
    }));
  });
});

// Subscribe to updates from other collaboration servers
sub.psubscribe('collab:*');
sub.on('pmessage', (pattern, channel, message) => {
  const projectId = channel.split(':')[1];
  const data = JSON.parse(message);

  // Forward to all WebSocket clients for this project (except sender)
  wss.clients.forEach((client) => {
    if (client.projectId === projectId && client.userId !== data.sender) {
      client.send(message);
    }
  });
});
```

## Scaling Strategies

### Container Orchestration

```
┌──────────────────────────────────────────────────────┐
│  Kubernetes Cluster for Sandboxes                     │
│                                                       │
│  Node Pool 1 (CPU-optimized):                        │
│    - 100 nodes * 32 vCPU = 3,200 sandboxes           │
│                                                       │
│  Node Pool 2 (Memory-optimized):                     │
│    - 50 nodes * 256GB RAM = Java/heavy workloads     │
│                                                       │
│  Auto-scaling:                                        │
│    - Pod HPA: scale sandbox pods based on demand     │
│    - Cluster autoscaler: add/remove nodes            │
│                                                       │
│  Security:                                            │
│    - Network policies: sandbox cannot reach other pods│
│    - Resource quotas per namespace                    │
│    - gVisor / Firecracker for kernel isolation        │
└──────────────────────────────────────────────────────┘
```

### File Storage Architecture

```
Active project (user is editing):
  Browser ←→ WebSocket ←→ CRDT Doc (memory) ←→ Periodic save to S3

Cold project (not active):
  Files stored in S3, loaded on-demand when user opens project

┌──────────┐    ┌──────────────┐    ┌──────────┐
│  Browser │───>│  File Server  │───>│   S3     │
│  (Monaco)│    │  (in-memory   │    │  (durable│
│          │<───│   buffer)     │<───│  storage)│
└──────────┘    └──────────────┘    └──────────┘
                      │
                      ▼
               ┌──────────────┐
               │  Sandbox PVC │  (mounted filesystem
               │  (ephemeral) │   for code execution)
               └──────────────┘
```

## Trade-offs

| Decision | Option A | Option B |
|---|---|---|
| **Isolation** | Docker containers | Firecracker microVMs |
| | Faster startup (~1s), shared kernel | Stronger isolation, ~125ms boot, more overhead |
| **Collaboration** | OT (Operational Transform) | CRDT (Yjs) |
| | Requires central server, simpler | Peer-to-peer capable, handles offline, complex merge |
| **File storage** | S3 + local cache | NFS shared volume |
| | Cheap, scalable, higher latency | Low latency, expensive, single point of failure |
| **Editor** | Monaco (VS Code engine) | CodeMirror 6 |
| | Feature-rich, heavier (~2MB) | Lighter, more customizable, mobile-friendly |
| **Sandbox lifecycle** | Always-on per project | On-demand (spin up on access) |
| | Instant access, expensive | Cold start delay (2-5s), much cheaper |

## Summary

An online code editor requires three core subsystems: a real-time collaborative editor (using CRDTs like Yjs for conflict-free merging), a sandboxed execution environment (Kubernetes pods or Firecracker microVMs with strict resource limits and network isolation), and a file management layer (S3 for durable storage with in-memory caching for active sessions). WebSocket connections handle bidirectional communication for keystrokes, terminal output, and cursor presence. The biggest scaling challenge is managing hundreds of thousands of concurrent sandboxes — Kubernetes cluster autoscaling with pod preemption for inactive users is the standard approach. Security is paramount: user code must be fully isolated from the host and other users via container security contexts, network policies, and optional kernel-level isolation with gVisor.

9.5.4.body:
# Design a Real-Time Collaborative Editor (Google Docs)

## Introduction

A real-time collaborative editor allows multiple users to simultaneously edit the same document with changes appearing instantly for all participants. Google Docs serves over 1 billion users and handles millions of concurrent editing sessions. This is widely considered one of the hardest system design problems because it demands conflict-free concurrent editing, real-time synchronization, rich text formatting, offline support, and version history — all while maintaining a responsive user experience.

This problem tests your deep understanding of distributed systems concurrency, CRDTs vs Operational Transformation, real-time communication patterns, and the challenges of building a system where consistency and responsiveness must coexist.

## Requirements

### Functional Requirements

1. **Create and manage documents** — Create, rename, delete, share documents
2. **Rich text editing** — Bold, italic, headings, lists, tables, images, links
3. **Real-time collaboration** — Multiple users edit simultaneously; changes appear within 100ms
4. **Cursor and selection presence** — See other users' cursors, selections, and names in real-time
5. **Comments and suggestions** — Add comments anchored to text ranges; suggest edits
6. **Version history** — View all changes with timestamps and authors; restore any version
7. **Offline editing** — Continue editing offline; sync when reconnected
8. **Access control** — Owner, editor, commenter, viewer permission levels
9. **Conflict resolution** — Concurrent edits never cause data loss or corruption

### Non-Functional Requirements

1. **Real-time latency** — Edits visible to collaborators within 100-200ms
2. **Consistency** — All users converge to the same document state (eventual consistency)
3. **Durability** — Zero data loss; every keystroke must eventually persist
4. **Scalability** — Support 50M concurrent documents, up to 100 editors per document
5. **Availability** — 99.99% uptime

## Capacity Estimation

```
Total users:                    1 billion
Daily active users:             300 million
Concurrent editing sessions:    50 million documents
Avg collaborators per document: 2-3 (up to 100)
Concurrent WebSocket connections: 80 million

Operations:
  - Keystrokes per active user: 3/sec average
  - Total operations: 80M * 3 = 240M operations/sec
  - After batching (50ms windows): 80M * 1 batch/50ms = 80M batched ops/sec
  - With compression: ~40M messages/sec over WebSockets

Storage:
  - Avg document size: 50KB (text + formatting)
  - Total documents: 5 billion
  - Document storage: 5B * 50KB = 250 TB
  - Version history (ops log): ~10x document size = 2.5 PB

Bandwidth:
  - Avg operation message: 100 bytes
  - Inbound: 240M * 100B = 24 GB/sec
  - Outbound (fan-out to collaborators): 24GB * 2 avg = 48 GB/sec
  - Total: ~72 GB/sec

WebSocket servers:
  - Each server handles ~50K connections
  - Servers needed: 80M / 50K = 1,600 WebSocket servers
```

